INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.13.67','cb','cb.adi.13','ЧБ Ади 13.67',67,'করিতে আছেন প্রভু শাস্ত্রের ব্যাখ্যান ।
‘হয়’ ‘নয়’ করে, ‘নয়’ করেন প্রমাণ ॥৬৭॥','карите а̄чхена прабху ш́а̄стрера вйа̄кхйа̄на̄
‘хайа’ найа’ каре, ‘найа’ карена прама̄н̣а',NULL,NULL),('cb.adi.13.68','cb','cb.adi.13','ЧБ Ади 13.68',68,'অনেক মণ্ডলী হই’ সর্ব্ব-শিষ্যগণ ।
চতুর্দ্দিকে বসিয়া আছেন সুশোভন ॥৬৮॥','анека ман̣д̣алӣ хаи’ сарва-ш́иш̣йа-ган̣а
чатур-дике васийа̄ а̄чхена суш́обхана',NULL,NULL),('cb.adi.13.69','cb','cb.adi.13','ЧБ Ади 13.69',69,'অপূর্ব্ব দেখিয়া দিগ্বিজয়ী সুবিস্মিত ।
মনে ভাবে,—“এই বুঝি নিমাইপণ্ডিত ?” ॥৬৯॥','апӯрва декхила̄ дигвиджайӣ сувисмита
мане бха̄ве, — ‘еи буджхи нима̄и пан̣д̣ита?’',NULL,NULL),('cb.adi.13.70','cb','cb.adi.13','ЧБ Ади 13.70',70,'অলক্ষিতে সেই স্থানে থাকি’ দিগ্বিজয়ী ।
প্রভুর সৌন্দর্য্য চা’হে একদৃষ্টি হই’ ॥৭০॥','алакш̣ите сеи стха̄не тха̄ки’ дигвиджайӣ
прабхура саундарйа са̄’хе эка-др̣ш̣т̣и хаи’',NULL,NULL),('cb.adi.13.71','cb','cb.adi.13','ЧБ Ади 13.71',71,'শিষ্যস্থানে জিজ্ঞাসিলা,—“কি নাম ইহান ?” ।
শিষ্য বোলে,—“নিমাইপণ্ডিত-খ্যাতি যা’ন” ॥৭১॥','ш́иш̣йа-стха̄не джиджн̃асила̄, — ‘ки на̄ма иха̄на?’
ш́иш̣йа боле, — ‘нима̄и пан̣д̣ита кхйа̄ти йа̄’на’',NULL,NULL),('cb.adi.13.72','cb','cb.adi.13','ЧБ Ади 13.72',72,'তবে গঙ্গা নমস্করি’ সেই বিপ্রবর ।
আইলেন ঈশ্বরের সভার ভিতর ॥৭২॥','табе ган̇га̄ намаскари’ сеи випра-вара
а̄илена ӣш́варера сабха̄ра бхитара',NULL,NULL),('cb.adi.13.73','cb','cb.adi.13','ЧБ Ади 13.73',73,'তানে দেখি’ প্রভু কিছু ঈষৎ হাসিয়া ।
বসিতে বলিলা অতি-আদর করিয়া ॥৭৩॥','та̄’не декхи’ прабху кичху ӣш̣ат ха̄сийа̄
васита балила̄ ати а̄дара карийа̄',NULL,NULL),('cb.adi.13.74','cb','cb.adi.13','ЧБ Ади 13.74',74,'পরম-নিঃশঙ্ক সেই, দিগ্বিজয়ী আর ।
তবু প্রভু দেখিয়া সাধ্বস হৈল তাঁর ॥৭৪॥','парама-них̣ш́ан̇ка сеи, дигвиджайӣ а̄ра
табу прабху декхила̄ са̄дхаваса хаила та̄н̇’ра',NULL,NULL),('cb.adi.13.75','cb','cb.adi.13','ЧБ Ади 13.75',75,'ঈশ্বর-স্বভাব-শক্তি এইমত হয় ।
দেখিতেই মাত্র তানে, সাধ্বস জন্ময় ॥৭৫॥','ӣш́вара-свабха̄ва-ш́акти эи-мата хайа
декхитеи ма̄тра та̄’не, са̄дхаваса джанмайа',NULL,NULL),('cb.adi.13.76','cb','cb.adi.13','ЧБ Ади 13.76',76,'সাত পাঁচ কথা প্রভু কহি’ বিপ্রসঙ্গে ।
জিজ্ঞাসিতে তাঁরে কিছু আরম্ভিলা রঙ্গে ॥৭৬॥
প্রভু কহে,—“তোমার কবিত্বের নাহি সীমা ।
হেন নাহি, যাহা তুমি না কর’ বর্ণনা ॥৭৭॥
গঙ্গার মহিমা কিছু করহ পঠন ।
শুনিয়া সবার হউক পাপ-বিমোচন” ॥৭৮॥
শুনি’ সেই দিগ্বিজয়ী প্রভুর বচন ।
সেইক্ষণে করিবারে লাগিলা বর্ণন ॥৭৯॥
দ্রুত যে লাগিলা বিপ্র করিতে বর্ণনা ।
কতরূপে বোলে, তার কে করিবে সীমা ? ॥৮০॥','са̄та па̄н̃ча катха̄ прабху кахи’ випра-сан̇ге
джиджн̃а̄сите та̄н̇’ре кичху а̄рамбхила̄ ран̇ге
прабху кахе, — ‘тома̄ра кавитвера нахи сӣма̄
хена на̄хи, йа̄ха̄ туми на̄ кара’ варн̣ана̄
ган̇га̄ра махима̄ кичху караха пат̣хана
ш́унийа̄ саба̄ра хаука па̄па-вимочана
ш́уни’ сеи дигвиджайӣ прабхура вачана
сеи-кш̣ан̣е кариба̄ре ла̄гила̄ варн̣ана
друта йе ла̄гила̄ випра карите варн̣ана̄
ката-рӯпе боле, та̄’ра ке карибе сӣма̄?',NULL,NULL),('cb.adi.13.81','cb','cb.adi.13','ЧБ Ади 13.81',81,'কত মেঘ, শুনি, যেন করয়ে গর্জ্জন ।
এইমত কবিত্বের গাম্ভীর্য্য-পঠন ॥৮১॥','ката мегха, ш́уни, йена карайе гарджана
йе-мата кавитвера га̄мбхӣрйа-пат̣хана',NULL,NULL),('cb.adi.13.82','cb','cb.adi.13','ЧБ Ади 13.82',82,'জিহ্বায় আপনি সরস্বতী-অধিষ্ঠান ।
যে বোলয়ে, সে-ই হয় অত্যন্ত-প্রমাণ ॥৮২॥','джихва̄йа а̄пани сарасватӣ-адхиш̣т̣ха̄на
йе болайе, се-и хайа атйанта-прама̄н̣а',NULL,NULL),('cb.adi.13.83','cb','cb.adi.13','ЧБ Ади 13.83',83,'মনুষ্যের শক্ত্যে তাহা দূষিবেক কে ? ।
হেন বিদ্যাবন্ত নাহি,—বুঝিবেক যে ॥৮৩॥','мануш̣йера ш́актйе та̄ха̄ дӯш̣ибека ке?
хена видйа̄ванта на̄хи, — буджхибека йе',NULL,NULL),('cb.adi.13.84','cb','cb.adi.13','ЧБ Ади 13.84',84,'সহস্র-সহস্র যত প্রভু শিষ্যগণ ।
অবাক্ হইলা সবে শুনিঞা বর্ণন ॥৮৪॥','сахасра-сахасра йата прабхура ш́иш̣йа-ган̣а
ава̄к хаила̄ сабе ш́унин̃а̄ варн̣ана',NULL,NULL),('cb.adi.13.85','cb','cb.adi.13','ЧБ Ади 13.85',85,'‘রাম রাম অদ্ভুত!’ স্মরেন শিষ্যগণ ।
‘মনুষ্যের এমত কি স্ফুরয়ে কথন?’ ॥৮৫॥','‘ра̄ма ра̄ма адбхута!’ смарена ш́иш̣йа-ган̣а
‘мануш̣йера э-мата ки спхурайе катхана?’',NULL,NULL),('cb.adi.13.86','cb','cb.adi.13','ЧБ Ади 13.86',86,'জগতে অদ্ভুত যত শব্দ-অলঙ্কার ।
সেই বই কবিত্বের বর্ণন নাহি আর ॥৮৬॥','джагате адбхута йата ш́абда-алан̇ка̄ра
сеи баи кавитвера варн̣ана на̄хи а̄ра',NULL,NULL),('cb.adi.13.87','cb','cb.adi.13','ЧБ Ади 13.87',87,'সর্ব্বশাস্ত্রে মহা-বিশারদ যে-যে-জন ।
হেন শব্দ তাঁ-সবারও বুঝিতে বিষম ॥৮৭॥','сарва-ш́а̄стре маха̄-виш́а̄рада йе-йе-джана
хена ш́абда та̄н̇’саба̄ра о буджхите виш̣ама',NULL,NULL),('cb.adi.13.88','cb','cb.adi.13','ЧБ Ади 13.88',88,'এইমত প্রহর-খানেক দিগ্বিজয়ী ।
অদ্ভুত সে পড়য়ে, তথাপি অন্ত নাই ॥৮৮॥','эи-мата прахара-кха̄нека дигвиджайӣ
адбхута се пад̣айе, татха̄пи анта на̄и',NULL,NULL),('cb.adi.13.89','cb','cb.adi.13','ЧБ Ади 13.89',89,'পড়ি’ যদি দিগ্বিজয়ী হৈলা অবসর ।
তবে হাসি’ বলিলেন শ্রীগৌরসুন্দর ॥৮৯॥','пад̣и’ йади дигвиджайӣ хаила̄ авасара
табе ха̄си’ балилена ш́рӣ-гаурасундара',NULL,NULL),('cb.adi.13.90','cb','cb.adi.13','ЧБ Ади 13.90',90,'“তোমার যে-শব্দের গ্রন্থন অভিপ্রায় ।
তুমি বিনে বুঝাইলে, বুঝা নাহি যায় ॥৯০॥','‘тома̄ра йе-ш́абдера грантхана абхипра̄йа
туми вине буджхаиле, буджха̄ на̄хи йа̄йа',NULL,NULL),('cb.adi.13.91','cb','cb.adi.13','ЧБ Ади 13.91',91,'এতেকে আপনে কিছু করহ ব্যাখ্যান ।
যে শব্দে যে বোল তুমি, সেই সুপ্রমাণ” ॥৯১॥','этеке а̄пане кичху караха вйа̄кхйа̄на
йе ш́абде йе бола туми, сеи супрама̄н̣а’',NULL,NULL),('cb.adi.13.92','cb','cb.adi.13','ЧБ Ади 13.92',92,'শুনিঞা প্রভুর বাক্য সর্ব্ব-মনোহর ।
ব্যাখ্যা করিবারে লাগিলেন বিপ্রবর ॥৯২॥','ш́унин̃а̄ прабхура ва̄кйа сарва-манохара
вйа̄кхйа̄ кариба̄ре ла̄гилена випра-вара',NULL,NULL),('cb.adi.13.93','cb','cb.adi.13','ЧБ Ади 13.93',93,'ব্যাখ্যা করিলেই মাত্র প্রভু সেইক্ষণে ।
দূষিলেন আদি-মধ্য-অন্তে তিন স্থানে ॥৯৩॥','вйа̄кхйа̄ карилеи ма̄тра прабху сеи-кш̣ан̣е
дӯш̣илена а̄ди-мадхйа-анте тина стха̄не',NULL,NULL),('cb.adi.13.94','cb','cb.adi.13','ЧБ Ади 13.94',94,'প্রভু বোলে,—“এ সকল শব্দ-অলঙ্কার ।
শাস্ত্র-মতে শুদ্ধ হৈতে বিষম অপার ॥৯৪॥','прабху боле, — ‘е сакала ш́абда-алан̇ка̄ра
ш́а̄стра-мате ш́уддха хаите виш̣ама апа̄ра',NULL,NULL),('cb.adi.13.95','cb','cb.adi.13','ЧБ Ади 13.95',95,'তুমি বা দিয়াছ কোন্ অভিপ্রায় করি’ ।
বোল দেখি ?” ক? হিলেন গৌরাঙ্গ শ্রীহরি ॥৯৫॥','туми ва̄ дийа̄чха кон абхипра̄йа кари’
бола декхи?’ кахилена гаура̄н̇га ш́рӣ-хари',NULL,NULL),('cb.adi.13.96','cb','cb.adi.13','ЧБ Ади 13.96',96,'এত বড় সরস্বতীপুত্ত্র দিগ্বিজয়ী ।
সিদ্ধান্ত না স্ফুরে কিছু, বুদ্ধি গেল কহিঁ ॥৯৬॥','эта бад̣а сарасватӣ-путра дигвиджайӣ
сиддха̄нта на̄ спхуре кичху, буддхи гела̄ кахин̇',NULL,NULL),('cb.adi.13.97','cb','cb.adi.13','ЧБ Ади 13.97',97,'সাত পাঁচ বোলে বিপ্র, প্রবোধিতে নারে ।
যেই বোলে, তাই দোষে গৌরাঙ্গসুন্দরে ॥৯৭॥','са̄та па̄н̃ча боле випра, прабодхите на̄ре
йеи боле, та̄и дош̣е гаура̄н̇га-сундара',NULL,NULL),('cb.adi.13.98','cb','cb.adi.13','ЧБ Ади 13.98',98,'সকল প্রতিভা পলাইল কোন্ স্থানে ।
আপনে না বুঝে বিপ্র, কি বোলে আপনে ॥৯৮॥','сакала пратибха̄ пала̄ила кон стха̄не
а̄пане на̄ буджхе випра, ки боле а̄пане',NULL,NULL),('cb.adi.13.99','cb','cb.adi.13','ЧБ Ади 13.99',99,'প্রভু বোলে,—“এ থাকুক, পড় কিছু আর” ।
পড়িতেও পূর্ব্বমত শক্তি নাহি আর ॥৯৯॥','прабху боле,—‘е т̣ха̄кука, пад̣а кичху а̄ра’
пад̣ите о пӯрва-мата ш́акти на̄хи а̄ра',NULL,NULL),('cb.adi.13.100','cb','cb.adi.13','ЧБ Ади 13.100',100,'কোন্ চিত্র তাহান সম্মোহ প্রভু-স্থানে ? ।
বেদেও পায়েন মোহ যাঁর বিদ্যমানে ॥১০০॥
আপনে অনন্ত, চতুর্ম্মুখ, পঞ্চানন ।
যাঁ’-সবার দৃষ্ট্যে হয় অনন্ত ভুবন ॥১০১॥
তাঁরাও পায়েন মোহ যাঁর বিদ্যমানে ।
কোন্ চিত্র,—সে বিপ্রের মোহ প্রভু-স্থানে ? ॥১০২॥','кон читра-та̄ха̄на саммоха прабху-стха̄не?
веде о па̄йена тоха йа̄н̇’ра видйама̄не
а̄пане ананта, чатурмукха, пан̃ча̄нана
йа̄н̇’саба̄ра др̣ш̣т̣йе хайа ананта бхувана
та̄н̇’ра о па̄йена моха йа̄н̇’ра видйама̄не
кон читра, — се випрера моха прабху-стха̄не',NULL,NULL),('cb.adi.13.103','cb','cb.adi.13','ЧБ Ади 13.103',103,'লক্ষ্মী-সরস্বতী-আদি যত যোগমায়া ।
অনন্ত-ব্রহ্মাণ্ড মোহে’ যাঁ’-সবার ছায়া ॥১০৩॥','лакш̣мӣ-сарасватӣ-а̄ди йата йогама̄йа̄
ананта-брахма̄н̣д̣а мохе’ йа̄н̇’саба̄ра чха̄йа̄',NULL,NULL),('cb.adi.13.104','cb','cb.adi.13','ЧБ Ади 13.104',104,'তাহারা পায়েন মোহ, যাঁর বিদ্যমানে ।
অতএব পাছে সে থাকেন সর্ব্বক্ষণে ॥১০৪॥','та̄ха̄ра̄ па̄йена моха, йа̄н̇’ра видйама̄не
атаева па̄чхе се тха̄кена сарва-кш̣ан̣е',NULL,NULL),('cb.adi.13.105','cb','cb.adi.13','ЧБ Ади 13.105',105,'বেদকর্ত্তা শেষও মোহ পায় যাঁর স্থানে ।
কোন্ চিত্র,—দিগ্বিজয়ী-মোহ বা তাহানে? ॥১০৫॥','веда-карта̄ ш́еш̣а о моха па̄йа йа̄н̇’ра стха̄не
кон читра, — дигвиджайӣ-моха ва̄ та̄ха̄не?',NULL,NULL),('cb.adi.13.106','cb','cb.adi.13','ЧБ Ади 13.106',106,'মনুষ্যে এ সব কার্য্য অসম্ভব বড় ।
তেঞি বলি,—তাঁর সকল কার্য্য দড় ॥১০৬॥','мануш̣йе э саба ка̄рйа асабхана бад̣а
тен̃и бали, — та̄н̇’ра сакала ка̄рйа дад̣а',NULL,NULL),('cb.adi.13.107','cb','cb.adi.13','ЧБ Ади 13.107',107,'মূলে যত কিছু কর্ম্ম করেন ঈশ্বরে ।
সকলি—নিস্তার-হেতু দুঃখিত-জীবেরে ॥১০৭॥','мӯле йата кичху карма карена ӣш́варе
сакали — ниста̄ра-хету дух̣кхита-джӣвере',NULL,NULL),('cb.adi.13.108','cb','cb.adi.13','ЧБ Ади 13.108',108,'দিগ্বিজয়ী যদি পরাজয়ে প্রবেশিলা ।
শিষ্যগণ হাসিবারে উদ্যত হইলা ॥১০৮॥','дигвиджайӣ йади пара̄джайе правеш́ила̄
ш́иш̣йа-ган̣а ха̄сиба̄ре удйата хаила̄',NULL,NULL),('cb.adi.13.109','cb','cb.adi.13','ЧБ Ади 13.109',109,'সবারেই প্রভু করিলেন নিবারণ ।
বিপ্র-প্রতি বলিলেন মধুর বচন ॥১০৯॥','саба̄реи прабху карилена нива̄ран̣а',NULL,NULL),('cb.adi.13.110','cb','cb.adi.13','ЧБ Ади 13.110',110,'“আজি চল তুমি শুভ কর’ বাসা-প্রতি ।
কালি বিচারিব সব তোমার সংহতি ॥১১০॥','«а̄джи чала туми ш́убха кара’ ва̄са̄-прати
ка̄ли вича̄риба саба тома̄ра сам̇хати',NULL,NULL),('cb.adi.13.111','cb','cb.adi.13','ЧБ Ади 13.111',111,'তুমিও হইলা শ্রান্ত অনেক পড়িয়া ।
নিশাও অনেক যায়, শুই থাক গিয়া” ॥১১১॥','туми о хаила̄ ш́ра̄нта анека пад̣ийа̄
ниш́а̄ о анека йа̄йа, ш́уи тха̄ка гийа’',NULL,NULL),('cb.adi.13.112','cb','cb.adi.13','ЧБ Ади 13.112',112,'এইমত প্রভুর কোমল ব্যবসায় ।
যাহারে জিনেন, সেহ দুঃখ নাহি পায় ॥১১২॥','эи-мата прабхура комала вйаваса̄йа
йа̄ха̄ре джинена, сеха дух̣кха на̄хи па̄йа',NULL,NULL),('cb.adi.13.113','cb','cb.adi.13','ЧБ Ади 13.113',113,'সেই নবদ্বীপে যত অধ্যাপক আছে ।
জিনিয়াও সবারে তোষেন প্রভু পাছে ॥১১৩॥','сеи навадвӣпе йата адхйа̄пака а̄чхе
джинийа̄ о саба̄ре тош̣ена прабху па̄чхе',NULL,NULL),('cb.adi.13.114','cb','cb.adi.13','ЧБ Ади 13.114',114,'“চল আজি ঘরে গিয়া বসি’ পুঁথি চাহ ।
কালি যে জিজ্ঞাসি’ তাহা বলিবারে চাহ” ॥১১৪॥','‘чала а̄джи гхаре гийа̄ васи’ пун̇тхи ча̄ха
ка̄ли йе джиджн̃а̄си’ та̄ха̄ балиба̄ре ча̄ха’',NULL,NULL),('cb.adi.13.115','cb','cb.adi.13','ЧБ Ади 13.115',115,'জিনিয়াও কারে না করেন তেজভঙ্গ ।
সবেই হয়েন প্রীত,—হেন তান রঙ্গ ॥১১৫॥','джинийа̄ о ка̄’ре на̄ карена теджа-бхан̇га
сабеи хайена прӣта, — хена та̄’на ран̇га',NULL,NULL),('cb.adi.13.116','cb','cb.adi.13','ЧБ Ади 13.116',116,'অতএব নবদ্বীপে যতেক পণ্ডিত ।
সবার প্রভুর প্রতি মনে বড় প্রীত ॥১১৬॥','атаева навадвӣпе йатека пан̣д̣ита
саба̄ра прабхура прати мане бад̣а прӣта',NULL,NULL),('cb.adi.13.117','cb','cb.adi.13','ЧБ Ади 13.117',117,'শিষ্যগণ-সংহতি চলিলা প্রভু ঘর ।
দিগ্বিজয়ী হৈলা বড় লজ্জিত-অন্তর ॥১১৭॥','ш́иш̣йа-ган̣а-сам̇хати чилила̄ прабху гхара
дигвиджайӣ хаила̄ бад̣а ладжджита-антара',NULL,NULL),('cb.adi.13.118','cb','cb.adi.13','ЧБ Ади 13.118',118,'দুঃখিত হইলা বিপ্র চিন্তে’ মনে-মনে ।
“সরস্বতী মোরে বর দিলেন আপনে ॥১১৮॥
ন্যায়, সাংখ্য, পাতঞ্জল, মীমাংসা-দর্শন ।
বৈশেষিক, বেদান্তে নিপুণ যত জন ॥১১৯॥
হেন জন না দেখিলুঁ সংসার-ভিতরে ।
জিনিতে কি দায়, মোর সনে কক্ষা করে ! ॥১২০॥','дух̣кхита хаила̄ випра чинте’ мане-мане
‘сарасватӣ торе вара дилена а̄пане
нйа̄йа, са̄н̇кхйа, па̄тан̃джала, мӣма̄м̇са-дарш́ана
ваиш́еш̣ика, веда̄нте нипун̣а йата джана
хена джана на̄ декхилун̇ сам̇са̄ра-бхитаре
джините ки да̄йа, мора сане какш̣а̄ каре!',NULL,NULL),('cb.adi.13.121','cb','cb.adi.13','ЧБ Ади 13.121',121,'শিশু-শাস্ত্র ব্যাকরণ পড়ায়ে ব্রাহ্মণ ।
সে মোরে জিনিল,—হেন বিধির ঘটন ! ॥১২১॥','ш́иш́у-ш́а̄стра вйа̄каран̣а пад̣а̄йе бра̄хман̣а
се море джинила,—хена видхира гхат̣ана!',NULL,NULL),('cb.adi.13.124','cb','cb.adi.13','ЧБ Ади 13.124',124,'অবশ্য ইহার আজি বুঝিব কারণ” ।
এত বলি’ মন্ত্র-জপে বসিলা ব্রাহ্মণ ॥১২৪॥','аваш́йа иха̄ра а̄джи буджхиба ка̄ран̣а’
эта бали’ мантра-джапе васила̄ бра̄хман̣а',NULL,NULL),('cb.adi.13.125','cb','cb.adi.13','ЧБ Ади 13.125',125,'মন্ত্র জপি’ দুঃখে বিপ্র শয়ন করিলা ।
স্বপ্নে সরস্বতী বিপ্র-সম্মুখে আইলা ॥১২৫॥','мантра джапи’ дух̣кхе випра ш́айана карила̄
свапне сарасватӣ випра-саммукхе а̄ила̄',NULL,NULL),('cb.adi.13.126','cb','cb.adi.13','ЧБ Ади 13.126',126,'কৃপা-দৃষ্ট্যে ভাগ্যবন্ত-ব্রাহ্মণের প্রতি ।
কহিতে লাগিলা অতি-গোপ্য সরস্বতী ॥১২৬॥','кр̣па̄-др̣ш̣т̣йе бха̄гйаванта-бра̄хман̣ера прати
кахите ла̄гила̄ ати-гопйа сарасватӣ',NULL,NULL),('cb.adi.13.127','cb','cb.adi.13','ЧБ Ади 13.127',127,'সরস্বতী বোলেন,—“শুনহ, বিপ্রবর ! ।
বেদ-গোপ্য কহি এই তোমার গোচর ॥১২৭॥
কারো স্থানে কহ যদি এ-সকল কথা ।
তবে তুমি শীঘ্র হৈবা অল্পায়ু সর্ব্বথা ॥১২৮॥
যাঁর ঠাঞি তোমার হইল পরাজয় ।
অনন্ত-ব্রহ্মা-নাথ সেই সুনিশ্চয় ॥১২৯॥','сарасватӣ болена, — ‘ш́унаха, випра-вара!
веда-гопйа кахи эи тома̄ра гочара
ка̄’ро стха̄не каха йади э-сакала катха̄
табе туми ш́ӣгхра хаиба̄ алпа̄йу сарватха̄
йа̄н̇’ра т̣ха̄н̃и тома̄ра хаила пара̄джайа
ананта-брахма̄н̣д̣а-на̄тха сеи суниш́чайа',NULL,NULL),('cb.adi.13.130','cb','cb.adi.13','ЧБ Ади 13.130',130,'আমি যাঁর পাদপদ্মে নিরন্তর দাসী ।
সম্মুখ হইতে আপনারে লজ্জা বাসি ॥১৩০॥','а̄ми йа̄н̇’ра па̄да-падме нирастара да̄сӣ
саммукха хаите а̄пана̄ре ладжджа̄ ва̄си',NULL,NULL),('cb.adi.13.131','cb','cb.adi.13','ЧБ Ади 13.131',131,'বিলজ্জমানয়া যস্য স্থাতুমীক্ষা-পথেঽমুয়া ।
বিমোহিতা বিকত্থন্তে মমাহমিতি-দুর্ধিয়ঃ ॥১৩১॥','виладжджама̄найа̄ йасйа
стха̄тум ӣкш̣а̄-патхе ’муйа̄
вимохита̄ викаттханте
мама̄хам ити дурдхийах̣',NULL,NULL),('cb.adi.13.132','cb','cb.adi.13','ЧБ Ади 13.132',132,'আমি সে বলিয়ে, বিপ্র, তোমার জিহ্বায় ।
তাহান সম্মুখে শক্তি না বসে আমায় ॥১৩২॥
আমার কি দায়, শেষ-দেব ভগবান্ ।
সহস্র-বদনে বেদ যে করে ব্যাখ্যান ॥১৩৩॥
অজ-ভব-আদি যাঁর উপাসনা করে ।
হেন ‘শেষ’ মোহ মানে যাঁহার গোচরে ॥১৩৪॥','а̄ми се балийе, випра, тома̄ра джихва̄йа
та̄ха̄на саммукхе ш́акти на̄ васе а̄ма̄йа
а̄ма̄ра ки да̄йа, ш́еш̣а-дева бхагава̄н
сахасра-вадане веда йе каре вйа̄кхйа̄на
аджа-бхава-а̄ди йа̄н̇’ра упа̄сана̄ каре
хена ‘ш́еш̣а’ моха ма̄не йа̄н̇ха̄ра гочаре',NULL,NULL),('cb.adi.13.135','cb','cb.adi.13','ЧБ Ади 13.135',135,'পরব্রহ্ম, নিত্য, শুদ্ধ, অখ, অব্যয় ।
পরিপূর্ণ হই’ বৈসে সবার হৃদয় ॥১৩৫॥','парабрахма, нитйа, ш́уддха, акхан̣д̣а, авйайа
парипӯрн̣а хаи’ ваисе саба̄ра хр̣дайа',NULL,NULL),('cb.adi.13.138','cb','cb.adi.13','ЧБ Ади 13.138',138,'আব্রহ্মাদি যত, দেখ, সুখ-দুঃখ পায় ।
সকল, জানিহ, বিপ্র, ইহান আজ্ঞায় ॥১৩৮॥','а̄брахма̄ди йата, декха, сукха-дух̣кха па̄йа
сакала, джа̄ниха, випра, иха̄на а̄джн̃а̄йа',NULL,NULL),('cb.adi.13.139','cb','cb.adi.13','ЧБ Ади 13.139',139,'মৎস্য-কূর্ম্ম-আদি যত, শুন, অবতার ।
এই প্রভু বিনা, বিপ্র, কিছু নহে আর ॥১৩৯॥','матсйа-кӯрма-а̄ди йата, ш́уна авата̄ра
эи прабху вина̄, випра, кичху нахе а̄ра',NULL,NULL),('cb.adi.13.140','cb','cb.adi.13','ЧБ Ади 13.140',140,'এই সে বরাহ-রূপে ক্ষিতি-স্থাপয়িতা ।
এই সে নৃসিংহ-রূপে প্রহ্লাদ-রক্ষিতা ॥১৪০॥','эи се вара̄ха-рӯпе кш̣ити-стха̄паита̄
эи се нр̣сим̇ха-рӯпе прахла̄да-ракш̣ита̄',NULL,NULL),('cb.adi.13.141','cb','cb.adi.13','ЧБ Ади 13.141',141,'এই সে বামন-রূপে বলির জীবন ।
যাঁর পাদপদ্ম হইতে গঙ্গার জনম ॥১৪১॥','эи се ва̄мана-рӯпе балира джӣвана
